class RoaringPositionBitmap:
    def __init__(self, buffer: bytes):
        self.buffer = buffer
        self.bitmap = RoaringBitmap.deserialize(buffer)

    def contains(self, row_offset: int) -> bool:
        return row_offset in self.bitmap
